import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Tabs, icon } from 'decantr/components';

code.example:
function CreatorProfile({ creator, tiers = [], posts = [], onSubscribe }) {
  const { div, h2, h3, p, span, nav, a, ul, li } = tags;
  const [activeTab, setActiveTab] = createSignal('posts');

  const tabs = [
    { id: 'posts', label: 'Posts', icon: 'grid', count: posts.length },
    { id: 'about', label: 'About', icon: 'user' },
    { id: 'tiers', label: 'Membership', icon: 'crown', count: tiers.length }
  ];

  return div({ class: css('_flex _col') },
    div({ class: css('_relative _h[240px] _md:h[320px] _overflow[hidden]') },
      creator.coverImage
        ? div({ style: `background-image:url(${creator.coverImage})`, class: css('_wfull _hfull _bgcover _bgcenter') })
        : div({ class: css('_wfull _hfull'), style: 'background:linear-gradient(135deg,#F97316,#8B5CF6)' }),
      div({ class: css('_absolute _inset0 _bg[linear-gradient(transparent_60%,rgba(0,0,0,0.5))]') })
    ),
    div({ class: css('_px4 _md:px8 _lg:px16 _pb8') },
      div({ class: css('_flex _col _md:row _aic _md:aie _gap6 _-mt16 _mb8') },
        div({ class: css('_w32 _h32 _r[50%] _overflow[hidden] _ring4 _ringbg _shadow _flex-shrink-0') },
          creator.avatar
            ? div({ style: `background-image:url(${creator.avatar})`, class: css('_wfull _hfull _bgcover _bgcenter') })
            : div({ class: css('_wfull _hfull _bgPrimary _flex _center _text[white] _heading2') }, creator.name[0])
        ),
        div({ class: css('_flex1 _tc _md:tl') },
          h2({ class: css('_heading2 _mb2') }, creator.name),
          p({ class: css('_fgmuted _mb4 _maxw[600px]') }, creator.tagline),
          div({ class: css('_flex _aic _jcc _md:jcs _gap4') },
            span({ class: css('_flex _aic _gap1') },
              icon('users', { size: '16', class: css('_fgmuted') }),
              span({ class: css('_fontmedium') }, creator.subscriberCount?.toLocaleString()),
              span({ class: css('_fgmuted') }, ' subscribers')
            ),
            span({ class: css('_flex _aic _gap1') },
              icon('file-text', { size: '16', class: css('_fgmuted') }),
              span({ class: css('_fontmedium') }, posts.length),
              span({ class: css('_fgmuted') }, ' posts')
            )
          )
        ),
        div({ class: css('_flex _gap2') },
          Button({ variant: 'outline' }, icon('share-2', { size: '18' })),
          Button({ variant: 'primary', class: css('studio-glow'), onclick: () => onSubscribe?.() }, 'Subscribe')
        )
      ),
      nav({ class: css('_flex _borderB _mb6') },
        ...tabs.map(tab =>
          a({
            class: css(`_flex _aic _gap2 _px4 _py3 _cursor[pointer] _trans _border-b-2 ${activeTab() === tab.id ? '_borderPrimary _fgPrimary' : '_borderTransparent _fgmuted _hover:fgfg'}`),
            onclick: () => setActiveTab(tab.id)
          },
            icon(tab.icon, { size: '18' }),
            tab.label,
            tab.count ? span({ class: css('_textsm _bgmuted/10 _px2 _r[999px]') }, tab.count) : null
          )
        )
      ),
      activeTab() === 'posts' ? div({ class: css('_grid _gc1 _lg:gc3 _gap6') },
        div({ class: css('_lg:gc2') },
          posts.length > 0 ? div({ class: css('_flex _col _gap4') },
            ...posts.map(post =>
              Card({ class: css('studio-card _overflow[hidden]') },
                post.thumbnail ? div({ class: css('_aspect[16/9] _bgmuted/10'), style: `background-image:url(${post.thumbnail});background-size:cover` }) : null,
                div({ class: css('_p4') },
                  h3({ class: css('_fontmedium _mb2') }, post.title),
                  p({ class: css('_textsm _fgmuted _lineClamp2') }, post.excerpt),
                  div({ class: css('_flex _jcsb _aic _mt3 _pt3 _borderT') },
                    span({ class: css('_textsm _fgmuted') }, new Date(post.createdAt).toLocaleDateString()),
                    div({ class: css('_flex _aic _gap2') },
                      span({ class: css('_flex _aic _gap1 _textsm _fgmuted') }, icon('heart', { size: '14' }), post.likes),
                      span({ class: css('_flex _aic _gap1 _textsm _fgmuted') }, icon('message-circle', { size: '14' }), post.comments)
                    )
                  )
                )
              )
            )
          ) : p({ class: css('_tc _fgmuted _py12') }, 'No posts yet')
        ),
        div({ class: css('_hidden _lg:flex _col _gap4') },
          h3({ class: css('_heading5 _mb2') }, 'Membership Tiers'),
          ...tiers.slice(0, 2).map(tier =>
            Card({ class: css('studio-card _p4') },
              div({ class: css('_flex _aic _gap2 _mb2') },
                div({ class: css('_w3 _h3 _r1'), style: `background:${tier.color || '#F97316'}` }),
                span({ class: css('_fontmedium') }, tier.name)
              ),
              p({ class: css('_heading4 _mb3') }, '$', tier.monthlyPrice, '/mo'),
              Button({ variant: 'outline', class: css('_wfull') }, 'Subscribe')
            )
          )
        )
      ) : null,
      activeTab() === 'about' ? Card({ class: css('studio-card _p6 _maxw[800px]') },
        h3({ class: css('_heading4 _mb4') }, 'About ', creator.name),
        p({ class: css('_fgmuted _whitespace[pre-wrap]') }, creator.bio || 'No bio yet.'),
        creator.socials?.length > 0 ? div({ class: css('_flex _gap3 _mt6 _pt6 _borderT') },
          ...creator.socials.map(s =>
            a({ href: s.url, target: '_blank', class: css('_flex _aic _gap2 _p2 _r2 _bgmuted/10 _trans _hover:bgmuted/20') },
              icon(s.platform === 'twitter' ? 'twitter' : s.platform === 'instagram' ? 'instagram' : 'link', { size: '18' }),
              span({ class: css('_textsm') }, s.label || s.platform)
            )
          )
        ) : null
      ) : null,
      activeTab() === 'tiers' ? div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6') },
        ...tiers.map((tier, i) =>
          Card({ class: css(`studio-card _p6 ${i === 1 ? 'studio-card-premium' : ''}`) },
            i === 1 ? span({ class: css('_textsm _fgSecondary _fontmedium _mb2 _block') }, 'Most Popular') : null,
            div({ class: css('_flex _aic _gap2 _mb2') },
              div({ class: css('_w4 _h4 _r1'), style: `background:${tier.color || '#F97316'}` }),
              h3({ class: css('_heading4') }, tier.name)
            ),
            p({ class: css('_textsm _fgmuted _mb4') }, tier.description),
            p({ class: css('_heading2 _mb4') }, '$', tier.monthlyPrice, '/mo'),
            ul({ class: css('_flex _col _gap2 _mb6') },
              ...tier.benefits.map(b =>
                li({ class: css('_flex _aic _gap2 _textsm') },
                  icon('check', { size: '16', class: css('_fgSuccess') }), b
                )
              )
            ),
            Button({ variant: i === 1 ? 'primary' : 'outline', class: css('_wfull'), onclick: () => onSubscribe?.(tier) }, 'Subscribe')
          )
        )
      ) : null
    )
  );
}

