function CreatorProfileEmbed({ creator, onSubscribe }) {
  const { div, span } = tags;

  return Card({ class: css('studio-card _p4 _flex _aic _gap4') },
    div({ class: css('_w12 _h12 _r[50%] _overflow[hidden]'), style: `background-image:url(${creator.avatar});background-size:cover` }),
    div({ class: css('_flex1') },
      span({ class: css('_fontmedium _block') }, creator.name),
      span({ class: css('_textsm _fgmuted') }, creator.subscriberCount, ' subscribers')
    ),
    Button({ variant: 'primary', onclick: onSubscribe }, 'Subscribe')
  );
}

